class Solution {
    public int getMinSwaps(String num, int k) {
        char[] arr = num.toCharArray();
        int n = arr.length;
        for (int i = 0; i < k; i++) {
            nextPermutation(arr);
        }
        int res = 0;
        for (int i = 0; i < n; i++) {
            if (arr[i] != num.charAt(i)) {
                int j = i + 1;
                while (j < n && arr[j] != num.charAt(i)) j++;
                while (j > i) {
                    char temp = arr[j];
                    arr[j] = arr[j - 1];
                    arr[j - 1] = temp;
                    res++;
                    j--;
                }
            }
        }
        return res;
    }

    private void nextPermutation(char[] arr) {
        int n = arr.length;
        int i = n - 2;
        while (i >= 0 && arr[i] >= arr[i + 1]) i--;
        if (i < 0) return;
        int j = n - 1;
        while (arr[j] <= arr[i]) j--;
        char temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
        int left = i + 1, right = n - 1;
        while (left < right) {
            temp = arr[left];
            arr[left] = arr[right];
            arr[right] = temp;
            left++;
            right--;
        }
    }
}
